1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const FP_EPSILON = 1e-9;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  rune: 25,
9	};
10	
11	type Item = { type: string; cursed?: boolean; enchantment?: number };
12	type Customer = { yearsWithMHPCO: number };
13	type Step = { op: "quote"; items: Item[] };
